#include <stdio.h>
#include <string.h>

int maxPairs(const char *s) {
    int n = strlen(s);
    int ans = 0;
    for (int i = 0; i + 1 < n; ) {
        if (s[i] != s[i + 1]) {
            ++ans;
            i += 2;
        } else {
            ++i;
        }
    }
    return ans;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char line[100005];
    while (T--) {
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        printf("%d\n", maxPairs(line));
    }
    return 0;
}

